11: #include "gmock/gmock.h"
12: #include "gtest/gtest.h"
13: 
14: namespace Envoy {
15: namespace Config {
16: namespace {
17: 
18: class InternalFactory : public Config::UntypedFactory {
19: public:
20:   ~InternalFactory() override = default;
21:   std::string category() const override { return ""; }
22: };
23: 
24: class TestInternalFactory : public InternalFactory {
25: public:
26:   std::string name() const override { return "testing.internal.test"; }
27: };
28: 
29: static Registry::RegisterInternalFactory<TestInternalFactory, InternalFactory>
30:     test_internal_register;
31: 
32: // Ensure that the internal test factory name isn't visible from a
33: // published category. Note that the internal factory can't be in
34: // a registered category by definition since it doesn't have a static
35: // category method.
36: TEST(RegistryTest, InternalFactoryNotPublished) {
37:   TestInternalFactory test;
38: 
39:   // Expect that the published categories don't lead to the internal factory.
40:   for (const auto& ext : Envoy::Registry::FactoryCategoryRegistry::registeredFactories()) {
41:     for (const auto& name : ext.second->registeredNames()) {
42:       EXPECT_NE(name, test.name());
43:     }
44:   }
45: 
46:   // Expect that the factory is present.
47:   EXPECT_NE(Registry::FactoryRegistry<InternalFactory>::getFactory("testing.internal.test"),
48:             nullptr);
49: }
50: 
51: class PublishedFactory : public Config::UntypedFactory {
52: public:
53:   ~PublishedFactory() override = default;
54:   std::string category() const override { return "testing.published"; }
55: };
56: 
57: class TestPublishedFactory : public PublishedFactory {
58: public:
59:   std::string name() const override { return "testing.published.test"; }
60: };
61: 
62: REGISTER_FACTORY(TestPublishedFactory, PublishedFactory);
63: 
64: TEST(RegistryTest, DefaultFactoryPublished) {
65:   const auto& factories = Envoy::Registry::FactoryCategoryRegistry::registeredFactories();
66: 
67:   // Expect that the category is present.
68:   ASSERT_NE(factories.find("testing.published"), factories.end());
69: 
70:   // Expect that the factory is listed in the right category.
71:   const auto& names = factories.find("testing.published")->second->registeredNames();
72:   EXPECT_NE(std::find(names.begin(), names.end(), "testing.published.test"), std::end(names));
73: 
74:   // Expect that the factory is present.
75:   EXPECT_NE(Registry::FactoryRegistry<PublishedFactory>::getFactory("testing.published.test"),
76:             nullptr);
77: 
78:   // Expect no version
79:   auto const version =
80:       factories.find("testing.published")->second->getFactoryVersion("testing.published.test");
81:   EXPECT_FALSE(version.has_value());
82: }
83: 
84: class TestVersionedFactory : public PublishedFactory {
85: public:
86:   std::string name() const override { return "testing.published.versioned"; }
87: };
88: 
89: REGISTER_FACTORY(TestVersionedFactory,
90:                  PublishedFactory){FACTORY_VERSION(2, 5, 39, {{"build.label", "alpha"}})};
91: 
92: // Test registration of versioned factory
93: TEST(RegistryTest, VersionedFactory) {
94:   const auto& factories = Envoy::Registry::FactoryCategoryRegistry::registeredFactories();
95: 
96:   // Expect that the category is present.
97:   ASSERT_NE(factories.find("testing.published"), factories.end());
98: 
99:   // Expect that the factory is listed in the right category.
100:   const auto& names = factories.find("testing.published")->second->registeredNames();
101:   EXPECT_NE(std::find(names.begin(), names.end(), "testing.published.versioned"), std::end(names));
102: 
103:   // Expect that the factory is present.
104:   EXPECT_NE(Registry::FactoryRegistry<PublishedFactory>::getFactory("testing.published.versioned"),
105:             nullptr);
106: 
107:   auto version =
108:       factories.find("testing.published")->second->getFactoryVersion("testing.published.versioned");
109:   EXPECT_TRUE(version.has_value());
110:   EXPECT_EQ(2, version.value().version().major_number());
111:   EXPECT_EQ(5, version.value().version().minor_number());
112:   EXPECT_EQ(39, version.value().version().patch());
113:   EXPECT_EQ(1, version.value().metadata().fields().size());
114:   EXPECT_EQ("alpha", version.value().metadata().fields().at("build.label").string_value());
115: }
116: 
117: TEST(RegistryTest, TestDoubleRegistrationByName) {
118:   EXPECT_THROW_WITH_MESSAGE((Registry::RegisterFactory<TestPublishedFactory, PublishedFactory>()),
119:                             EnvoyException,
120:                             "Double registration for name: 'testing.published.test'");
121: }
122: 
123: } // namespace
124: } // namespace Config
125: } // namespace Envoy
