9: namespace Envoy {
10: namespace Extensions {
11: namespace HttpFilters {
12: namespace Geoip {
13: 
14: Http::FilterFactoryCb GeoipFilterFactory::createFilterFactoryFromProtoTyped(
15:     const envoy::extensions::filters::http::geoip::v3::Geoip& proto_config,
16:     const std::string& stat_prefix, Server::Configuration::FactoryContext& context) {
17:   GeoipFilterConfigSharedPtr filter_config(
18:       std::make_shared<GeoipFilterConfig>(proto_config, stat_prefix, context.scope()));
19: 
20:   const auto& provider_config = proto_config.provider();
21:   auto& geo_provider_factory =
22:       Envoy::Config::Utility::getAndCheckFactory<Geolocation::GeoipProviderFactory>(
23:           provider_config);
24:   ProtobufTypes::MessagePtr message = Envoy::Config::Utility::translateToFactoryConfig(
25:       provider_config, context.messageValidationVisitor(), geo_provider_factory);
26:   auto driver = geo_provider_factory.createGeoipProviderDriver(*message, stat_prefix, context);
27:   return [filter_config, driver](Http::FilterChainFactoryCallbacks& callbacks) -> void {
28:     callbacks.addStreamDecoderFilter(std::make_shared<GeoipFilter>(filter_config, driver));
29:   };
30: }
31: 
32: /**
33:  * Static registration for geoip filter. @see RegisterFactory.
34:  */
35: REGISTER_FACTORY(GeoipFilterFactory,
36:                  Server::Configuration::NamedHttpFilterConfigFactory){"envoy.geoip"};
37: 
38: } // namespace Geoip
39: } // namespace HttpFilters
40: } // namespace Extensions
41: } // namespace Envoy
